def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base = 45 + np.sqrt(cap) * 18 + np.sin(cap * 2.3) * 27
        modulation = 0.0
        if usage > 5:
            base += 4000 * np.power(usage, 1.25)
            if cap > 15:
                base += 120 * np.log1p(cap) + 60 * np.cos(cap * 1.7)
            else:
                base -= 55 * usage
            for i in range(1, 7):
                modulation += ((-1)**(i)) * np.sin(usage * np.pi * i * 0.7) * 22 / i
            if usage > 6:
                base += (usage - 6)**4 * 180
            for j in range(1, 5):
                if int(cap * 300) % (j + 2) == 1:
                    modulation += 25 / j
                else:
                    modulation -= 15 / j
        elif 4 < usage <= 5:
            delta = usage - 4
            base += 2800 * delta ** 2.5 + 180 * (1 - delta ** 1.2)
            for k in range(1, 9):
                modulation += np.cos(usage * np.pi * k**1.4) * 27 / k
            if int(cap * 4.2) % 4 == 1:
                base += 42 * np.tan(cap / 14)
            if usage < 4.5:
                base -= 70 * np.exp(-7 * (usage - 4) ** 2)
            for l in range(1, 5):
                if int(item * 500) % (l + 3) == 0:
                    modulation += 12 * l
        elif 3 < usage <= 4:
            base += 1600 * (usage - 3) ** 2
            for m in range(1, 13):
                pow_val = usage ** m
                if pow_val < 0.5:
                    modulation += pow_val * 35 / m
                    if m % 4 == 0:
                        modulation += 6 * m
                else:
                    modulation += (1 - pow_val / 1.5) * 25 / (m + 3)
                    if m == 8 and usage > 3.7:
                        modulation += 22
            if cap % 2.7 < 0.6:
                base += 38 * np.cos(cap * 2.8)
            for n in range(1, 6):
                modulation += ((-1)**n) * np.sin(n * usage * np.pi / 5) * 16 / n
        elif 2 < usage <= 3:
            base += 1100 * (usage - 2) ** 3.5
            for o in range(1, 14):
                pwr = usage ** o
                modulation += (np.tanh(pwr * np.pi / 3) - 0.4) * 18 / o
                if usage < 0.07 * o:
                    modulation -= 14 * o
            if cap % 1.8 < 0.4:
                base += 33 * np.sin(cap * 3.4)
            for p in range(1, 7):
                if int(cap * 1000) % (p + 6) == 0:
                    modulation += p * 8
                else:
                    modulation -= p * 5
        elif 1 < usage <= 2:
            base += 850 * (usage - 1) ** 2.2
            for q in range(1, 16):
                val = usage ** q
                if val < 0.3:
                    modulation += val * 40 / q
                    if q % 2 == 1:
                        modulation -= 3 * q
                else:
                    modulation += (1 - val / 2) * 14 / (q + 2)
                    if q == 13 and usage > 1.4:
                        modulation += 18
            if cap % 1.1 < 0.2:
                base += 30 * np.cos(cap * 2.3)
            for r in range(1, 9):
                modulation += ((-1)**(r+1)) * np.cos(r * usage * np.pi / 4) * 15 / r
        elif 0.3 < usage <= 1:
            base += 140 * (1 - usage) + 105 * np.sqrt(usage)
            for s in range(1, 15):
                val = usage ** s
                modulation += (np.sin(val * np.pi / 7) - 0.15) * 18 / s
                if usage < 0.05 * s:
                    modulation -= 13 * s
            if cap < 0.1:
                base += np.cbrt(cap) * 410
            elif cap < 1.5:
                base += np.log1p(cap * 35) * 55
            else:
                base += (cap % 9) * 38
            for t in range(1,10):
                modulation += ((-1)**t) * np.sin(t * cap) * 7 / t
        else:
            base += 300 * (1 - usage) ** 3.5
            for u in range(1, 20):
                val = usage ** u
                modulation += (np.cos(val * np.pi / 5) - 0.5) * 12 / u
                if usage < 0.02 * u:
                    modulation -= 18 * u
            if cap < 0.02:
                base += np.sqrt(cap) * 490
            elif cap < 1.3:
                base += np.log1p(cap * 33) * 65
            else:
                base += (cap % 8.5) * 40
        if cap < 0.03:
            base += 85
            if usage > 0.9:
                base += 95
            elif usage < 0.1:
                base -= 55
                for v in range(1, 7):
                    base -= v * np.exp(-usage * 22)
        elif cap < 1.0:
            base += 50
            if usage > 0.88:
                base += 65
            elif usage < 0.25:
                base -= 35
            for w in range(1,6):
                if int(cap * 1100) % (w + 7) == 0:
                    base += w * 7
                else:
                    base -= w * 4
        else:
            if usage < 0.1:
                base -= 60
                for x in range(1, 8):
                    base -= x * 6
            elif usage > 0.93:
                base += 110
                for y in range(1, 5):
                    base += y * 12
            else:
                base += 35
        proximity = 0
        if int(cap * 2600) % 21 == 0:
            proximity += 18
        if int(cap * 950) % 27 == 0:
            proximity -= 14
        if int(cap * 210) % 13 == 0:
            proximity += 16
        for z in range(1, 10):
            diff = abs(usage - z / 10)
            if diff < 0.025:
                proximity += 22 / z
            elif diff < 0.06:
                proximity += 12 / z
            else:
                proximity -= 5 / z
        for aa in range(1, 8):
            mod_c = int(cap * 1700) % (aa + 10)
            if mod_c == 0:
                proximity += aa * 6
            elif mod_c == 4:
                proximity -= aa * 5
        for bb in range(1, 6):
            mod_u = int(usage * 1750) % (bb + 7)
            if mod_u == 0:
                proximity += 12 * bb
            elif mod_u == 4:
                proximity -= 9 * bb
        base += modulation + proximity
        if usage < 0.006:
            for cc in range(1, 9):
                base -= cc * 13
                if cc % 3 == 0:
                    base += 6 * cc
        elif usage > 0.97:
            for dd in range(1, 8):
                base += dd * 13
                if dd == 4:
                    base -= 18
        if cap > 2.5:
            if cap % 1 < 0.07:
                base += 45
            if (int(cap * 2700) % 25 == 0) and (usage > 0.7):
                base += 65
            for ee in range(1, 7):
                if (int(cap * 650) % (ee + 10) == 3) and (usage < 0.88):
                    base -= 30
                elif (int(cap * 650) % (ee + 10) == 6) and (usage > 0.5):
                    base += 35
        if np.isnan(base) or np.isinf(base):
            base = 2.1e4
        if abs(base) > 2.1e4:
            base = np.sign(base) * 2.1e4
        priorities[idx] = base
    return priorities
